CREATE DATABASE IF NOT EXISTS plc_db;
USE plc_db;

DROP TABLE IF EXISTS `plc_oee_activities`;
CREATE TABLE `plc_oee_activities` (
  `device` varchar(10) DEFAULT NULL,
  `station_id` int(2) DEFAULT NULL,
  `plc_id` int(2) DEFAULT NULL,
  `value` varchar(100) DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_activities_master`;
CREATE TABLE `plc_oee_activities_master` (
  `device` varchar(10) NOT NULL,
  `station_id` int(11) DEFAULT NULL,
  `plc_id` int(11) DEFAULT NULL,
  `value` varchar(255) DEFAULT '0',
  `updated_at` datetime DEFAULT current_timestamp(),
  `status_read` int(1) DEFAULT 0,
  PRIMARY KEY (`device`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `plc_oee_delay_activities`;
CREATE TABLE `plc_oee_delay_activities` (
  `device` varchar(5) DEFAULT NULL,
  `station_id` int(4) DEFAULT NULL,
  `plc_id` int(4) DEFAULT NULL,
  `value` int(1) DEFAULT NULL,
  `comment` varchar(100) DEFAULT NULL,
  `start_time` datetime DEFAULT NULL,
  `end_time` datetime DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_delay_time_master`;
CREATE TABLE `plc_oee_delay_time_master` (
  `device` varchar(10) NOT NULL,
  `station_id` int(11) DEFAULT NULL,
  `plc_id` int(11) DEFAULT NULL,
  `value` tinyint(1) DEFAULT 0,
  `comment` varchar(255) DEFAULT NULL,
  `updated_at` datetime DEFAULT current_timestamp(),
  `start_time` datetime DEFAULT current_timestamp(),
  `end_time` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`device`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `plc_oee_fault_activities`;
CREATE TABLE `plc_oee_fault_activities` (
  `device` varchar(5) DEFAULT NULL,
  `value` int(11) DEFAULT NULL,
  `plc_id` int(11) DEFAULT NULL,
  `comment` varchar(100) DEFAULT NULL,
  `start_time` datetime DEFAULT current_timestamp(),
  `endtime` datetime DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_fault_master`;
CREATE TABLE `plc_oee_fault_master` (
  `device` varchar(10) NOT NULL,
  `plc_id` int(11) DEFAULT NULL,
  `value` tinyint(1) DEFAULT NULL,
  `comment` varchar(255) DEFAULT NULL,
  `updated_at` datetime DEFAULT current_timestamp(),
  `start_time` datetime DEFAULT NULL,
  `end_time` datetime DEFAULT NULL,
  PRIMARY KEY (`device`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `plc_oee_got_activity`;
CREATE TABLE `plc_oee_got_activity` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `device` varchar(50) NOT NULL,
  `value` varchar(50) DEFAULT '0',
  `komen` text DEFAULT NULL,
  `start_time` datetime DEFAULT NULL,
  `end_time` datetime DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_device` (`device`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_seat_ng_ok_activity`;
CREATE TABLE `plc_oee_seat_ng_ok_activity` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `device` varchar(50) DEFAULT NULL,
  `station_id` varchar(50) DEFAULT NULL,
  `value` text DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_seat_ng_ok_master`;
CREATE TABLE `plc_oee_seat_ng_ok_master` (
  `device` varchar(50) NOT NULL,
  `value` varchar(50) DEFAULT '0',
  `station_id` int(11) DEFAULT NULL,
  `comment` text DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  UNIQUE KEY `unique_device_station` (`device`,`station_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `plc_oee_seat_result_activity`;
CREATE TABLE `plc_oee_seat_result_activity` (
  `device` varchar(50) DEFAULT NULL,
  `station_id` varchar(50) DEFAULT NULL,
  `seq` varchar(50) DEFAULT NULL,
  `model` varchar(50) DEFAULT NULL,
  `dest` varchar(50) DEFAULT NULL,
  `grade` varchar(50) DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_seat_result_detail`;
CREATE TABLE `plc_oee_seat_result_detail` (
  `device` varchar(50) NOT NULL,
  `value` varchar(50) DEFAULT '0',
  `station_id` int(11) DEFAULT NULL,
  `comment` text DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  UNIQUE KEY `unique_device_station` (`device`,`station_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_seat_text_input`;
CREATE TABLE `plc_oee_seat_text_input` (
  `device` varchar(50) NOT NULL,
  `value` varchar(50) DEFAULT '0',
  `station_id` int(11) DEFAULT NULL,
  `comment` text DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  UNIQUE KEY `unique_device_station` (`device`,`station_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_seat_text_input_activity`;
CREATE TABLE `plc_oee_seat_text_input_activity` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `device` varchar(50) DEFAULT NULL,
  `station_id` varchar(50) DEFAULT NULL,
  `value` text DEFAULT NULL,
  `update_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_total_fault_activity`;
CREATE TABLE `plc_oee_total_fault_activity` (
  `device` varchar(10) DEFAULT NULL,
  `station_id` int(11) DEFAULT NULL,
  `plc_id` int(11) DEFAULT NULL,
  `value` varchar(100) DEFAULT NULL,
  `comment` varchar(100) DEFAULT NULL,
  `update_at` datetime DEFAULT current_timestamp(),
  `start_time` datetime DEFAULT NULL,
  `end_time` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `plc_oee_total_fault_master`;
CREATE TABLE `plc_oee_total_fault_master` (
  `device` varchar(10) NOT NULL,
  `station_id` int(11) DEFAULT NULL,
  `plc_id` int(11) DEFAULT NULL,
  `value` varchar(255) DEFAULT '0',
  `comment` varchar(255) DEFAULT NULL,
  `updated_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`device`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


